import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect } from 'react';
import { HashRouter as Router, Routes, Route, Link, useLocation } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { Phone, Calendar, MapPin, Clock, Instagram, Facebook, Share2, Menu as MenuIcon, X, ChefHat } from 'lucide-react';

// Components
import Home from './pages/Home';
import MenuPage from './pages/Menu';
import AboutPage from './pages/About';
import SpacePage from './pages/Space';
import HoursPage from './pages/Hours';
import ReservationPage from './pages/Reservation';
import AIConcierge from './components/AIConcierge';

const Navbar = () => {
  const [isOpen, setIsOpen] = useState(false);
  const location = useLocation();

  const navLinks = [
    { name: 'Menu', path: '/menu' },
    { name: 'About', path: '/about' },
    { name: 'Our Space', path: '/space' },
    { name: 'Hours', path: '/hours' },
  ];

  return (
    <nav className="fixed top-0 left-0 w-full z-50 px-4 py-4 md:px-8 md:py-6">
      <div className="max-w-7xl mx-auto flex items-center justify-between bg-black/40 backdrop-blur-md border border-white/10 rounded-2xl px-6 py-3">
        <Link to="/" className="flex items-center gap-2 group">
          <div className="w-8 h-8 bg-emerald-500 rounded-lg flex items-center justify-center transition-transform group-hover:rotate-12">
            <span className="font-bold text-black text-xs">SS</span>
          </div>
          <span className="text-xl font-serif tracking-tight">Sora Sushi</span>
        </Link>

        {/* Desktop Nav */}
        <div className="hidden md:flex items-center gap-8">
          {navLinks.map((link) => (
            <Link
              key={link.path}
              to={link.path}
              className={`text-sm font-medium transition-colors hover:text-emerald-400 ${
                location.pathname === link.path ? 'text-emerald-500' : 'text-gray-300'
              }`}
            >
              {link.name}
            </Link>
          ))}
        </div>

        <div className="hidden md:flex items-center gap-4">
          <button className="flex items-center gap-2 px-4 py-2 border border-white/20 rounded-xl text-sm font-medium hover:bg-white/5 transition-colors">
            <Phone size={16} />
            <span>Call</span>
          </button>
          <Link to="/reservation" className="flex items-center gap-2 px-4 py-2 bg-emerald-500 text-black rounded-xl text-sm font-bold hover:bg-emerald-400 transition-colors shadow-lg shadow-emerald-500/20">
            <Calendar size={16} />
            <span>Book a Table</span>
          </Link>
        </div>

        {/* Mobile Toggle */}
        <button className="md:hidden text-white" onClick={() => setIsOpen(!isOpen)}>
          {isOpen ? <X /> : <MenuIcon />}
        </button>
      </div>

      {/* Mobile Menu Overlay */}
      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0, y: -20 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -20 }}
            className="absolute top-24 left-4 right-4 bg-zinc-900/95 backdrop-blur-xl border border-white/10 rounded-3xl p-6 flex flex-col gap-6 md:hidden shadow-2xl z-50"
          >
            {navLinks.map((link) => (
              <Link
                key={link.path}
                to={link.path}
                onClick={() => setIsOpen(false)}
                className="text-2xl font-serif"
              >
                {link.name}
              </Link>
            ))}
            <hr className="border-white/10" />
            <div className="flex flex-col gap-3">
              <button className="flex items-center justify-center gap-2 w-full py-4 border border-white/20 rounded-2xl text-lg">
                <Phone /> Call
              </button>
              <Link
                to="/reservation"
                onClick={() => setIsOpen(false)}
                className="flex items-center justify-center gap-2 w-full py-4 bg-emerald-500 text-black rounded-2xl text-lg font-bold"
              >
                <Calendar /> Book a Table
              </Link>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </nav>
  );
};

const App: React.FC = () => {
  return (
    <Router>
      <div className="min-h-screen bg-[#0a0a0a] selection:bg-emerald-500/30">
        <Navbar />
        <main className="pt-24 pb-32">
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/menu" element={<MenuPage />} />
            <Route path="/about" element={<AboutPage />} />
            <Route path="/space" element={<SpacePage />} />
            <Route path="/hours" element={<HoursPage />} />
            <Route path="/reservation" element={<ReservationPage />} />
          </Routes>
        </main>

        {/* Floating AI Chef Assistance */}
        <AIConcierge />

        {/* Global Footer (Visible on all pages) */}
        <footer className="fixed bottom-0 left-0 w-full p-4 md:p-8 z-40">
          <div className="max-w-7xl mx-auto flex flex-col md:flex-row items-center justify-between gap-4 bg-black/40 backdrop-blur-md border border-white/10 rounded-2xl px-8 py-4 text-xs md:text-sm text-gray-400">
            <div className="flex flex-wrap items-center justify-center gap-6">
              <div className="flex items-center gap-2">
                <MapPin size={14} className="text-emerald-500" />
                <span>124 Minami Ave, Tokyo</span>
              </div>
              <div className="flex items-center gap-2 border-l border-white/10 pl-6">
                <Clock size={14} className="text-emerald-500" />
                <span>Open today 12:00–23:00</span>
              </div>
            </div>
            <div className="flex items-center gap-4">
              <button className="hover:text-white transition-colors"><Instagram size={18} /></button>
              <button className="hover:text-white transition-colors"><Facebook size={18} /></button>
              <button className="hover:text-white transition-colors"><Share2 size={18} /></button>
            </div>
          </div>
        </footer>
      </div>
    </Router>
  );
};

export default App;

